module shift_register(CLK, RST, LOAD, PARALLEL_IN, SERIAL_OUT);
input CLK, RST, LOAD;
input [7:0] PARALLEL_IN;
output SERIAL_OUT;
reg [7:0] data_reg;
assign SERIAL_OUT = data_reg[7];

always @(posedge CLK or posedge RST) begin
    if (RST)
        data_reg <= 0;
    else if (LOAD)
        data_reg <= PARALLEL_IN;
    else
        data_reg <= {data_reg[6:0], 1'b0};
end

endmodule
